DROP VIEW IF EXISTS nexus_validation_stats; CREATE VIEW nexus_validation_stats AS SELECT c.id as civilization_id, c.name as civilization_name, COUNT(v.id) as validation_count, COUNT(CASE WHEN v.can_be_negated = false THEN 1 END) as robust_count, COUNT(CASE WHEN v.can_be_negated = true THEN 1 END) as negable_count, AVG(v.quipu_cognitive) as avg_cognitive, AVG(v.quipu_resonant) as avg_resonant, COUNT(CASE WHEN v.geometric_pattern = 'P1' THEN 1 END) as p1_count, COUNT(CASE WHEN v.geometric_pattern = 'P2' THEN 1 END) as p2_count, COUNT(CASE WHEN v.geometric_pattern = 'P3' THEN 1 END) as p3_count, COUNT(CASE WHEN v.geometric_pattern = 'P4' THEN 1 END) as p4_count FROM nexus_civilizations c LEFT JOIN nexus_validations v ON c.id = v.civilization_id GROUP BY c.id, c.name; COMMENT ON VIEW nexus_validation_stats IS 'Estadísticas de calibraciones F0 por civilización con métricas QUIPU';
